class SubscriptionTierEnum(graphene.Enum):
    FREE = "free"
    BASIC = "basic"
    PRO = "pro"
    ENTERPRISE = "enterprise"


class RoleEnum(graphene.Enum):
    USER = "user"
    MODERATOR = "moderator"
    ADMIN = "admin"


class UserType(ObjectType):
    id = String(required=True)
    username = String(required=True)
    email = String(required=True)
    bio = String()
    role = String(required=True)
    is_admin = Boolean(required=True)
    credits = Int(required=True)
    subscription_tier = String(required=True)


class UpdateUserProfile(Mutation):
    """
    Mutation for updating user profiles.
    
    Security model:
    - Regular users can only update their OWN profile and only safe fields
      (username, email, bio).
    - Admin users can update ANY user's profile and ALL fields including
      privileged ones (role, is_admin, credits, subscription_tier).
    - A target_user_id can be provided by admins to update another user's profile.
    """

    class Arguments:
        target_user_id = String(
            description="ID of the user to update. Admins only. Defaults to authenticated user."
        )
        username = String(description="New username")
        email = String(description="New email address")
        bio = String(description="New bio text")
        role = RoleEnum(description="New role (admin only)")
        is_admin = Boolean(description="Admin status (admin only)")
        credits = Int(description="Credit balance (admin only)")
        subscription_tier = SubscriptionTierEnum(
            description="Subscription tier (admin only)"
        )

    user = Field(UserType)
    success = Boolean(required=True)
    message = String(required=True)

    @staticmethod
    def validate_email(email):
        if email is not None:
            if not email or "@" not in email or "." not in email.split("@")[-1]:
                raise ValueError(f"Invalid email address: {email}")
            # Check for uniqueness
            for uid, user_data in USERS_DB.items():
                if user_data["email"] == email:
                    # Will be checked against target user later
                    return email
        return email

    @staticmethod
    def validate_username(username):
        if username is not None:
            if not username or len(username) < 3:
                raise ValueError("Username must be at least 3 characters long")
            if len(username) > 50:
                raise ValueError("Username must be at most 50 characters long")
            if not username.replace("_", "").replace("-", "").isalnum():
                raise ValueError(
                    "Username can only contain alphanumeric characters, underscores, and hyphens"
                )
        return username

    @staticmethod
    def validate_bio(bio):
        if bio is not None:
            if len(bio) > 500:
                raise ValueError("Bio must be at most 500 characters long")
        return bio

    @staticmethod
    def validate_credits(credits):
        if credits is not None:
            if credits < 0:
                raise ValueError("Credits cannot be negative")
        return credits

    def mutate(
        self,
        info,
        target_user_id=None,
        username=None,
        email=None,
        bio=None,
        role=None,
        is_admin=None,
        credits=None,
        subscription_tier=None,
    ):
        # Get authenticated user from context
        authenticated_user = info.context.get("authenticated_user") if info.context else None

        if not authenticated_user:
            return UpdateUserProfile(
                user=None, success=False, message="Authentication required"
            )

        auth_user_id = authenticated_user["id"]
        auth_is_admin = authenticated_user.get("is_admin", False)

        # Determine target user
        effective_target_id = target_user_id if target_user_id else auth_user_id

        # Non-admins cannot update other users' profiles
        if not auth_is_admin and effective_target_id != auth_user_id:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="Permission denied: you can only update your own profile",
            )

        # Check target user exists
        if effective_target_id not in USERS_DB:
            return UpdateUserProfile(
                user=None, success=False, message="Target user not found"
            )

        target_user = USERS_DB[effective_target_id]

        # Define privileged fields that only admins can modify
        PRIVILEGED_FIELDS = {
            "role": role,
            "is_admin": is_admin,
            "credits": credits,
            "subscription_tier": subscription_tier,
        }

        # Check if non-admin is trying to set privileged fields
        if not auth_is_admin:
            attempted_privileged = [
                field_name
                for field_name, field_value in PRIVILEGED_FIELDS.items()
                if field_value is not None
            ]
            if attempted_privileged:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Permission denied: only admins can modify {', '.join(attempted_privileged)}",
                )

        # Validate inputs
        try:
            UpdateUserProfile.validate_username(username)
            UpdateUserProfile.validate_email(email)
            UpdateUserProfile.validate_bio(bio)
            UpdateUserProfile.validate_credits(credits)
        except ValueError as e:
            return UpdateUserProfile(user=None, success=False, message=str(e))

        # Check username uniqueness
        if username is not None:
            for uid, user_data in USERS_DB.items():
                if uid != effective_target_id and user_data["username"] == username:
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Username '{username}' is already taken",
                    )

        # Check email uniqueness
        if email is not None:
            for uid, user_data in USERS_DB.items():
                if uid != effective_target_id and user_data["email"] == email:
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Email '{email}' is already in use",
                    )

        # Apply updates
        updates_applied = []

        # Safe fields (any authenticated user can update their own)
        if username is not None:
            target_user["username"] = username
            updates_applied.append("username")

        if email is not None:
            target_user["email"] = email
            updates_applied.append("email")

        if bio is not None:
            target_user["bio"] = bio
            updates_applied.append("bio")

        # Privileged fields (admin only - already checked above)
        if role is not None:
            # Graphene enum .value gives us the string value
            target_user["role"] = role if isinstance(role, str) else role.value
            updates_applied.append("role")

        if is_admin is not None:
            target_user["is_admin"] = is_admin
            updates_applied.append("is_admin")

        if credits is not None:
            target_user["credits"] = credits
            updates_applied.append("credits")

        if subscription_tier is not None:
            target_user["subscription_tier"] = (
                subscription_tier
                if isinstance(subscription_tier, str)
                else subscription_tier.value
            )
            updates_applied.append("subscription_tier")

        if not updates_applied:
            return UpdateUserProfile(
                user=UserType(**target_user),
                success=True,
                message="No fields to update were provided",
            )

        updated_user = UserType(**target_user)

        return UpdateUserProfile(
            user=updated_user,
            success=True,
            message=f"Successfully updated: {', '.join(updates_applied)}",
        )


class Query(ObjectType):
    me = Field(UserType, description="Get the currently authenticated user's profile")
    user = Field(
        UserType,
        user_id=String(required=True),
        description="Get a user by ID (admin only)",
    )
    all_users = graphene.List(UserType, description="List all users (admin only)")

    def resolve_me(self, info):
        authenticated_user = info.context.get("authenticated_user") if info.context else None
        if not authenticated_user:
            return None
        user_id = authenticated_user["id"]
        if user_id in USERS_DB:
            return UserType(**USERS_DB[user_id])
        return None

    def resolve_user(self, info, user_id):
        authenticated_user = info.context.get("authenticated_user") if info.context else None
        if not authenticated_user or not authenticated_user.get("is_admin", False):
            return None
        if user_id in USERS_DB:
            return UserType(**USERS_DB[user_id])
        return None

    def resolve_all_users(self, info):
        authenticated_user = info.context.get("authenticated_user") if info.context else None
        if not authenticated_user or not authenticated_user.get("is_admin", False):
            return []
        return [UserType(**user_data) for user_data in USERS_DB.values()]


class MutationType(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=MutationType)


def execute_query(query_string, context=None, variables=None):
    """Helper to execute a GraphQL query with context."""
    result = schema.execute(
        query_string, context=context or {}, variables=variables or {}
    )
    if result.errors:
        print(f"Errors: {result.errors}")
    if result.data:
        print(f"Data: {result.data}")
    return result


